sysevent_script_action.script:
// Handler for x_dice_digicertone.EnrollmentCreated
// Fired when the Certificate Request, created basing on profile with DTA enrollment, is approved
var logger = new Logger('EnrollmentCreatedHandler');
logger.debug('Starting script action');

var MAX_EVENTS = 2;
var payload = JSON.parse(event.parm1);
var eventNumber = payload.eventNumber; // event number in this event's chain
var certificateRequestSysId = payload.certificateRequestSysId;
var enrollmentId = payload.enrollmentId;

logger.debug('Handling the event {0}, related to certificate request record. Payload: {1}.', event.name, event.parm1);

var certificateRequestService = new CertificateRequestService();
var result = certificateRequestService.getCertsForCreatedEnrollments(enrollmentId);

if (result === true) {
  logger.debug('Certificate has been added already, nothing to update. enrollmentId - {0}', enrollmentId);
} else if (result.length === 1 && result[0].enrollmentId === enrollmentId) {
  logger.debug('Certificate has been retrieved and added. enrollmentId - {0}', enrollmentId);
} else if (eventNumber < MAX_EVENTS) {
  // In general we should poll DC1 API for certificate 2 times:
  //   - in 1 hour after enrollment creation
  //   - then in 2 hours
  // After that, stop polling, even though the certificate has not been installed.
  // The certificate will be retrieved by Scheduled Executed Script - GetCertsForCreatedEnrollments.
  logger.debug('No certificate retrieved. Submit event to run an action again. enrollmentId - {0}', enrollmentId);

  var eventName = 'x_dice_digicertone.EnrollmentCreated';
  var nextEventNumber = eventNumber + 1;
  var expiration = new GlideDateTime();
  expiration.addSeconds(3600 * nextEventNumber); // 3600 * eventNumber seconds
  var payload = JSON.stringify({
    eventNumber: nextEventNumber,
    certificateRequestSysId: certificateRequestSysId,
    enrollmentId: enrollmentId,
  });
  gs.eventQueueScheduled(eventName, '', payload, gs.getUserName(), expiration);
}

logger.debug('Finished script action');
